using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public sealed class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public sealed class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string PredictedCategory { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public sealed record TicketRequest(string Subject, string Description, int Priority);

public sealed record PredictionResponse(
    string PredictedCategory,
    Dictionary<string, float> Confidence);

public sealed record EvaluationResponse(
    double MicroAccuracy,
    double MacroAccuracy,
    double LogLoss,
    double LogLossReduction,
    ConfusionMatrixInfo ConfusionMatrix);

public sealed record ConfusionMatrixInfo(
    IReadOnlyList<string> Classes,
    IReadOnlyList<IReadOnlyList<double>> Counts);

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public sealed class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly string _dataPath;
    private readonly string _modelPath;
    private PredictionEngine<TicketData, TicketPrediction>? _predictionEngine;
    private IReadOnlyList<string>? _classLabels;
    private readonly Lock _lock = new();

    public bool IsModelTrained => _predictionEngine is not null;

    public TicketClassifierService(IWebHostEnvironment env)
    {
        _mlContext = new MLContext(seed: 42);
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public EvaluationResponse TrainAndEvaluate()
    {
        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Combine text features and build pipeline
        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(_mlContext)
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // With a small dataset, train on all data and evaluate on the same set
        // to report metric baselines. A production system would use cross-validation.
        var model = pipeline.Fit(dataView);

        var predictions = model.Transform(dataView);
        var metrics = _mlContext.MulticlassClassification.Evaluate(
            predictions, labelColumnName: "Label");

        _mlContext.Model.Save(model, dataView.Schema, _modelPath);

        // Extract ordered class labels from the key-value mapping
        var labelColumn = predictions.Schema["Label"];
        var keyType = labelColumn.Type as Microsoft.ML.Data.KeyDataViewType;
        VBuffer<ReadOnlyMemory<char>> keyValues = default;
        labelColumn.GetKeyValues(ref keyValues);
        _classLabels = keyValues.DenseValues()
            .Select(v => v.ToString()).ToList();

        lock (_lock)
        {
            _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(model);
        }

        var cm = metrics.ConfusionMatrix;
        var counts = cm.Counts
            .Select(row => (IReadOnlyList<double>)row.ToList())
            .ToList();

        return new EvaluationResponse(
            MicroAccuracy: metrics.MicroAccuracy,
            MacroAccuracy: metrics.MacroAccuracy,
            LogLoss: metrics.LogLoss,
            LogLossReduction: metrics.LogLossReduction,
            ConfusionMatrix: new ConfusionMatrixInfo(
                cm.PerClassPrecision.Count > 0
                    ? _classLabels
                    : [],
                counts));
    }

    public PredictionResponse Predict(TicketRequest request)
    {
        PredictionEngine<TicketData, TicketPrediction> engine;
        lock (_lock)
        {
            engine = _predictionEngine
                ?? throw new InvalidOperationException(
                    "Model has not been trained. POST to /api/tickets/train first.");
        }

        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = engine.Predict(input);

        var confidence = new Dictionary<string, float>();
        if (_classLabels is not null)
        {
            for (var i = 0; i < _classLabels.Count && i < prediction.Score.Length; i++)
            {
                confidence[_classLabels[i]] = prediction.Score[i];
            }
        }

        return new PredictionResponse(prediction.PredictedCategory, confidence);
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController(TicketClassifierService classifier) : ControllerBase
{
    /// <summary>Trains the model and returns evaluation metrics.</summary>
    [HttpPost("train")]
    public ActionResult<EvaluationResponse> Train()
    {
        var result = classifier.TrainAndEvaluate();
        return Ok(result);
    }

    /// <summary>Predicts the category for a support ticket.</summary>
    [HttpPost("predict")]
    public ActionResult<PredictionResponse> Predict([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) ||
            string.IsNullOrWhiteSpace(request.Description))
        {
            return BadRequest("Subject and Description are required.");
        }

        if (request.Priority is < 1 or > 3)
        {
            return BadRequest("Priority must be between 1 and 3.");
        }

        if (!classifier.IsModelTrained)
        {
            return Conflict(new { error = "Model has not been trained. POST to /api/tickets/train first." });
        }

        var prediction = classifier.Predict(request);
        return Ok(prediction);
    }
}

