using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController(TicketClassifierService classifier) : ControllerBase
{
    /// <summary>Trains the model and returns evaluation metrics.</summary>
    [HttpPost("train")]
    public ActionResult<EvaluationResponse> Train()
    {
        var result = classifier.TrainAndEvaluate();
        return Ok(result);
    }

    /// <summary>Predicts the category for a support ticket.</summary>
    [HttpPost("predict")]
    public ActionResult<PredictionResponse> Predict([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) ||
            string.IsNullOrWhiteSpace(request.Description))
        {
            return BadRequest("Subject and Description are required.");
        }

        if (request.Priority is < 1 or > 3)
        {
            return BadRequest("Priority must be between 1 and 3.");
        }

        if (!classifier.IsModelTrained)
        {
            return Conflict(new { error = "Model has not been trained. POST to /api/tickets/train first." });
        }

        var prediction = classifier.Predict(request);
        return Ok(prediction);
    }
}

